// let: 再代入可能
let count = 0;
count = count + 1; // ✅

// var: 関数スコープ、巻き上げあり（非推奨）
var old = 'avoid';

// スコープの違い
function scopeDemo() {
    var x = 'function scope';
    let y = 'block scope';
    if (true) {
        var x = 'same variable!'; // 上書きされる
        let y = 'new variable';   // 別の変数
        const z = 'block only';
    }
    console.log(x); // 'same variable!'
    console.log(y); // 'block scope'
    // console.log(z); // ❌ ReferenceError
}

